import React, { useEffect, useState } from 'react'
import Header from './Header';
import { test_img } from '../assets/img';

export const Game = () => {
    const [imgWidth, setImgWidth] = useState(0)
    const [imgHeight, setImgHeight] = useState(0)

  return (
    <div className='flex flex-col h-screen'>
        <Header/>
        <div className='flex flex-1 w-full justify-center overflow-hidden'>
            <img src={test_img} className=' h-full object-contain'
            onLoad={
                (e) => {
                    setImgWidth(e.currentTarget.width)
                    setImgHeight(e.currentTarget.height)
                }
            }
            />
        </div>
        <div>
        <TextBox text={"hello"} speed={100} />
        <div
            className="overflow-hidden fixed h-16 bg-[rgba(128,128,255,0.5)] blur-md  bottom-0 left-1/2 -translate-x-1/2"
            style={{
                width: `${imgWidth}px`,
                height: `${imgHeight/3}px`
            }}
        >
        </div>
        </div>


    </div>
  )
}
const TextBox = ({height, width, name, text, speed}) => {

    const [currentText, setCurrentText] = useState("")    
    useEffect(() => {
        setCurrentText("")
        let index = 0;        
        const typingWord = setInterval(() => {
            if(index < text.length) {
                index++;
                // console.log(index);
                setCurrentText(text.slice(0, index));
                // console.log(text.slice(0, index));
                // console.log(currentText)
            }         
        }, speed)

        return () => clearInterval(typingWord); 
    }, [speed, text])

    useEffect(() => {
        console.log("Updated currentText:", currentText);

    }, [currentText]);

    return (
            <span className='text-3xl'>{currentText}</span>
    )
}

export default Game;
